// Normalize Tally form payload into flat, English-named fields.
// IMPORTANT: Update the field labels below to match YOUR Tally form's question labels.
const input = items[0].json;
const fields = input.body.data.fields || [];

// Get first or nth occurrence of a field by label
function getFieldValue(label, index = 0) {
  const matches = fields.filter(f => f.label?.trim() === label.trim());
  return matches[index] ? matches[index].value : '';
}

// Get dropdown text of first or nth occurrence
function getDropdownText(label, index = 0) {
  const matches = fields.filter(f => f.label?.trim() === label.trim());
  const field = matches[index];
  if (!field || !field.options) return '';
  const selectedId = Array.isArray(field.value) ? field.value[0] : field.value;
  const option = field.options.find(opt => opt.id === selectedId);
  return option ? option.text : '';
}

return [
  {
    json: {
      // Service Provider (looked up from Airtable)
      provider_id: getFieldValue("Service Provider"),
      provider_name: getDropdownText("Service Provider"),

      // Subject (person the contract is about)
      subject_name: getFieldValue("Subject Full Name"),
      subject_dob: getFieldValue("Date of Birth"),
      subject_address: getFieldValue("Address", 0),

      // Primary Contact (e.g. parent, guardian, or main signer)
      primary_contact_name: getFieldValue("Primary Contact Full Name"),
      primary_contact_address: getFieldValue("Address", 1),
      primary_contact_email: getFieldValue("Email", 0),
      primary_contact_phone: getFieldValue("Phone", 0),

      // Secondary Contact (e.g. second parent/guardian)
      secondary_contact_name: getFieldValue("Secondary Contact Full Name"),
      secondary_contact_address: getFieldValue("Address", 2),
      secondary_contact_email: getFieldValue("Email", 1),
      secondary_contact_phone: getFieldValue("Phone", 1),

      // Service details
      service_start_date: getFieldValue("Service Start Date"),
      service_schedule: getFieldValue("Service Schedule"),
      signing_arrangement: getDropdownText("Signing Arrangement")
    }
  }
];
